mapping = {
    "name": "Name",
    "department": "Department",
    "manager": "Manager",
    "role": "Role",
    "email": "Email",
}

for item in _items:
    data = item["json"]

    search_by = (data.get("search_by") or "").lower().strip()
    search_value = (data.get("search_value") or "").strip()

    if search_by not in mapping:
        raise Exception(
            f"search_by must be one of: {', '.join(mapping.keys())}"
        )

    if not search_value:
        raise Exception("search_value cannot be empty")

    item["json"] = {
        "column": mapping[search_by],
        "value": search_value,
    }

return _items

def normalize(text):
    if text is None:
        return ""

    return " ".join(str(text).lower().split())


# ---------------------------------------
# Get the search request
# ---------------------------------------

search_item = None
staff = []

for item in _items:
    data = item["json"]

    if "column" in data and "value" in data:
        search_item = data
    else:
        staff.append(data)

if search_item is None:
    raise Exception("Search request not found.")

column = search_item["column"]
search_value = normalize(search_item["value"])

search_words = set(search_value.split())

results = []

for row in staff:

    cell = normalize(row.get(column, ""))

    cell_words = set(cell.split())

    score = len(search_words & cell_words)

    # Exact contains
    if search_value in cell:
        score += 100

    # Word matches
    score += len(search_words.intersection(cell_words))

    if score > 0:
        row["_score"] = score
        results.append({
            "json": row
        })

results.sort(
    key=lambda x: x["json"]["_score"],
    reverse=True
)

return results
